// DetectarPedidoHumano — sobrescreve nodo_atual='aguarda_humano' se necessario
const ss = $input.first().json;
let mensagem = '';
try { mensagem = String($('Entrada').first().json.mensagem || '').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, ''); } catch(e) {}

const KEYWORDS_HUMANO = [
  'atendente', 'vendedor', 'humano', 'pessoa', 'consultor', 'operador',
  'falar com voce', 'falar com alguem', 'ajuda', 'socorro',
  'nao consigo', 'nao tenho', 'sem foto', 'sem rg', 'sem cnh',
  'depois', 'mais tarde', 'desisto', 'desistir',
  'cancelar', 'cancela',
];

const pediu_humano = KEYWORDS_HUMANO.some(k => mensagem.includes(k));

// Conta tentativas CONSECUTIVAS no mesmo estado. Se o cliente avancou
// (estado mudou desde a ultima mensagem), reinicia a contagem.
const dados = ss.dados || {};
const estado_atual = ss.nodo_atual;
const tentativas_key = `_tentativas_${estado_atual}`;
const mudou_de_estado = dados._ultimo_estado_visto !== estado_atual;
const tentativas_anteriores = mudou_de_estado ? 0 : (dados[tentativas_key] || 0);
const tentativas = tentativas_anteriores + 1;
// Avalia sobre a contagem ANTERIOR: a mensagem atual sempre tem chance de
// ser validada. So vai pra humano se ja falhou 5x antes desta mensagem.
const muito_erro = tentativas_anteriores >= 5;

if (pediu_humano || muito_erro) {
  return [{ json: {
    ...ss,
    nodo_atual: 'aguarda_humano',
    dados: {
      ...dados,
      _ultimo_estado_visto: estado_atual,
      motivo_handoff: pediu_humano ? 'cliente_pediu' : 'muitas_tentativas',
      estado_anterior: estado_atual,
      mensagem_handoff: mensagem.slice(0, 200),
    }
  }}];
}

return [{ json: {
  ...ss,
  dados: { ...dados, [tentativas_key]: tentativas, _ultimo_estado_visto: estado_atual }
}}];

// ClassificarPosConcluido — sim (novo pedido) / nao (humano)
let raw = '';
try { raw = $('Entrada').first().json.mensagem || ''; } catch(e) {}
const m = String(raw).trim().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const NOVO = ['sim','s','novo','novo pedido','quero','outro','recomecar','recomeçar','reiniciar','de novo'];
const HUMANO = ['nao','n','consultor','humano','atendente','vendedor','falar com','pessoa'];
let r = 'unknown';
if (NOVO.some(w => m === w || m.startsWith(w + ' '))) r = 'novo';
else if (HUMANO.some(w => m === w || m.startsWith(w + ' '))) r = 'humano';
return [{ json: { confirmacao: r } }];

// ClassificarCampoCorrigir — detecta qual campo cliente quer ajustar
let raw = '';
try { raw = $('Entrada').first().json.mensagem || ''; } catch(e) {}
const m = String(raw).trim().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const MAPA = {
  nome:        ['nome', 'meu nome'],
  cep:         ['cep', 'endereco', 'endereço', 'cidade', 'bairro', 'rua'],
  numero:      ['numero', 'número', 'numero da casa'],
  complemento: ['complemento', 'apto', 'apartamento', 'bloco'],
  plano:       ['plano', 'mega', 'pacote', 'internet'],
  cpf:         ['cpf', 'documento'],
  data_nasc:   ['data', 'nascimento', 'data de nascimento', 'idade', 'aniversario'],
  email:       ['email', 'e-mail', 'mail'],
  rg:          ['rg', 'foto', 'identidade', 'cnh', 'documento'],
};

let campo_alvo = null;
for (const [campo, keywords] of Object.entries(MAPA)) {
  for (const kw of keywords) {
    if (m === kw || m.includes(' ' + kw) || m.includes(kw + ' ') || m.startsWith(kw)) {
      campo_alvo = campo;
      break;
    }
  }
  if (campo_alvo) break;
}

return [{ json: {
  ...$input.first().json,
  campo_alvo: campo_alvo || 'desconhecido',
}}];

// SmartSkip — quando tudo preenchido, vai direto pro resumo final
const CAMPOS_OBRIGATORIOS = [
  'nome', 'cep', 'numero', 'plano_id', 'cpf',
  'data_nascimento', 'email', 'doc_rg_frente_url', 'doc_rg_verso_url'
];

const item = $input.first().json;
const dados = item.novas_vars || {};
const proximo = item.proximo_nodo;

// Correcao de campo em andamento — nunca pula pro resumo
if (item.forcar_sem_skip === true) { return [{ json: item }]; }

// Estados terminais ou de fluxo especial — passa direto
const ESTADOS_NAO_PULAR = [
  'concluido', 'aguarda_humano', 'aguarda_confirmacao_final',
  'aguarda_decisao_pos_concluido', 'aguarda_decisao_correcao'
];
if (ESTADOS_NAO_PULAR.includes(proximo)) {
  return [{ json: item }];
}

// Verifica se TODOS os campos obrigatorios estao preenchidos
const todos_preenchidos = CAMPOS_OBRIGATORIOS.every(c => !!dados[c]);
if (!todos_preenchidos) {
  return [{ json: item }];
}

// Tudo preenchido — pula pra confirmacao final com resumo
const cep = dados.cep || '';
const complemento = dados.complemento ? ` - ${dados.complemento}` : '';
  const rua = dados.rua ? `${dados.rua}, ` : '';
const resumo =
  `Pronto! ✅ Atualizei seus dados. Confere se tá tudo certo:

` +
  `👤 *Nome:* ${dados.nome}
` +
  `📧 *Email:* ${dados.email}
` +
  `🆔 *CPF:* ${dados.cpf}
` +
  `🎂 *Nascimento:* ${dados.data_nascimento}

` +
  `📍 *Endereço:*
` +
  `   ${rua}${dados.numero}${complemento}
` +
  `   ${dados.bairro || ''} - ${dados.cidade || ''}/${dados.estado || ''}
` +
  `   CEP: ${cep}

` +
  `📡 *Plano:* ${dados.plano_interesse}

` +
  `📎 RG frente + verso recebidos

` +
  `Posso confirmar? (sim/não)`;

return [{ json: {
  ...item,
  proximo_nodo: 'aguarda_confirmacao_final',
  resposta_bot: resumo,
}}];

// ValidarNome — rejeita vazio/curto/sem letras/lixo
let raw = '';
try { raw = $('Entrada').first().json.mensagem || ''; } catch(e) {}
const trimmed = String(raw).trim();

// Regras:
// 1. Minimo 2 caracteres
// 2. Pelo menos 50% das letras (filtra "asdfgh" e numeros)
// 3. Max 150 caracteres (trunca)
// 4. Deve ter pelo menos 1 letra
let valido = trimmed.length >= 2 && trimmed.length <= 150;
if (valido) {
  const letras = (trimmed.match(/[a-zA-ZáéíóúâêîôûãõàèìòùçÁÉÍÓÚÂÊÎÔÛÃÕÀÈÌÒÙÇñÑ]/g) || []).length;
  const total = trimmed.replace(/\s/g, '').length;
  valido = letras >= 2 && (total === 0 || letras / total >= 0.5);
}

// Capitalizar primeira letra de cada palavra (cosmetic)
const formatted = valido ? trimmed.split(/\s+/).map(w =>
  w.length > 0 ? w[0].toUpperCase() + w.slice(1).toLowerCase() : w
).join(' ').slice(0, 150) : trimmed;

return [{ json: {
  nome_input: raw,
  nome_formatado: formatted,
  nome_valido: valido,
}}];

