// Preserva o output do Load Session no flow data
// HTTP node antes deste substituiu o $json — recupera do node por nome.
const ls = $node['Load Session'].json;
const hub = $input.first().json;  // output do Consultar Hubtrix Estado

return [{ json: {
  telefone:    ls.telefone,
  nodo_atual:  ls.nodo_atual,
  dados:       ls.dados || {},
  // extras pra IF/regras consultarem
  hubtrix_modo:     hub.modo_atendimento || null,
  hubtrix_existe:   hub.existe || false,
  hubtrix_agente:   hub.agente_id || null,
}}];

// ValidarExtras - parse "1,2,3" ou "4" ou variações
const EXTRAS = [
  {id:'X1', label:'Wi-Fi 6',            valor:10.00},
  {id:'X2', label:'Linha Fixa',         valor:19.99},
  {id:'X3', label:'Repetidor de Sinal', valor:29.99},
];

let mensagem = '';
try { mensagem = $('Entrada').first().json.mensagem || ''; } catch(e) {}
mensagem = String(mensagem).trim();

// Aceitar separadores comuns: virgula, espaco, ponto-virgula, barra, +, e, traco
const numeros = mensagem.split(/[,;\/\s\+\-]+/).map(s => s.trim()).filter(Boolean);

let escolhidos = [];
let pulou = false;
let invalido = false;

for (const tok of numeros) {
  const n = parseInt(tok, 10);
  if (isNaN(n)) { invalido = true; break; }
  if (n === 4) { pulou = true; break; }       // 4 = continuar sem extras
  if (n < 1 || n > 3) { invalido = true; break; }
  const ext = EXTRAS[n - 1];
  if (ext && !escolhidos.find(e => e.id === ext.id)) escolhidos.push(ext);
}

// Se misturou 4 com outros: invalido
if (pulou && escolhidos.length > 0) invalido = true;

const valor_extras_total = escolhidos.reduce((s, e) => s + e.valor, 0);

return [{ json: {
  acrescimos: escolhidos.map(e => e.label),
  acrescimos_ids: escolhidos.map(e => e.id),
  valor_extras_total: valor_extras_total,
  pulou_extras: pulou,
  camada1_ok: !invalido && (pulou || escolhidos.length > 0),
}}];

// ValidarConfirmacaoExtras - match 1/sim/confirmar vs 2/alterar/nao
let mensagem = '';
try { mensagem = $('Entrada').first().json.mensagem || ''; } catch(e) {}
const msg = String(mensagem).trim().toLowerCase();

const SIM = ['1', 'sim', 's', 'confirmar', 'confirma', 'pode', 'ok', 'beleza'];
const NAO = ['2', 'alterar', 'altera', 'nao', 'não', 'mudar', 'troca', 'trocar'];

let acao = null;
if (SIM.includes(msg) || SIM.some(p => msg.startsWith(p + ' '))) acao = 'confirmar';
else if (NAO.includes(msg) || NAO.some(p => msg.startsWith(p + ' '))) acao = 'alterar';

return [{ json: { acao: acao, camada1_ok: acao !== null }}];

