// GerarCatalogoPlanos — gera grupo, planos e lista formatada (Brayo)
// Le cidade de duas fontes: HTTP ViaCEP (turno do CEP) ou Load Session.dados.cidade (turno do plano)
function normCidade(s) {
  return (s || '').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '');
}
let cidade = '';
try { cidade = $('HTTP ViaCEP').first().json.localidade; } catch(e) {}
if (!cidade) { try { cidade = $('Load Session').first().json.dados.cidade; } catch(e) {} }
const cidadeNorm = normCidade(cidade);

// Brayo atende somente estas cidades. Demais -> transbordo humano.
const GRUPO_POR_CIDADE = {
  'lencois paulista': 'BRAYO',
  'macatuba':         'BRAYO',
  'pederneiras':      'BRAYO',
};

const PLANOS = {
  BRAYO: [
    {id:'P1', vel:400,  label:'400 Mega', pix:74.99, boleto:74.99},
    {id:'P2', vel:600,  label:'600 Mega', pix:89.99, boleto:89.99},
    {id:'P3', vel:1000, label:'1000 Mega', pix:99.99, boleto:99.99},
  ]
};

const grupo = GRUPO_POR_CIDADE[cidadeNorm] || null;

// Cidade fora da area -> sinaliza transbordo (nodos a jusante decidem)
if (!grupo) {
  return [{ json: {
    cidade: cidade,
    grupo: null,
    atende: false,
    transbordo: true,
    motivo: 'cidade_fora_area',
    planos: [],
    catalogo_json: '[]',
    lista_formatada: 'Ainda nao atendemos sua regiao. Vou te transferir para um atendente.',
  }}];
}

const planos = PLANOS[grupo];
const EMOJI_NUM = ['1️⃣','2️⃣','3️⃣','4️⃣','5️⃣','6️⃣','7️⃣','8️⃣','9️⃣'];
const lista_formatada = '📶 *Planos disponíveis:*\n\n' + planos.map((p, i) => {
  const num = EMOJI_NUM[i] || `${i+1}.`;
  const pix = p.pix.toFixed(2).replace('.', ',');
  return `${num} ${p.label} por R$ ${pix}`;
}).join('\n\n');

return [{ json: {
  cidade: cidade,
  grupo: grupo,
  atende: true,
  transbordo: false,
  planos: planos,
  catalogo_json: JSON.stringify(planos),
  lista_formatada: lista_formatada,
}}];

// ValidarEscolhaPlano (Camada 1) — matcha numero ou velocidade (Brayo)
function normCidade(s) {
  return (s || '').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '');
}
let cidade = '';
try { cidade = $('Load Session').first().json.dados.cidade; } catch(e) {}
const cidadeNorm = normCidade(cidade);

const GRUPO_POR_CIDADE = {
  'lencois paulista': 'BRAYO',
  'macatuba':         'BRAYO',
  'pederneiras':      'BRAYO',
};
const PLANOS = {
  BRAYO: [
    {id:'P1', vel:400,  label:'400 Mega', pix:74.99, boleto:74.99},
    {id:'P2', vel:600,  label:'600 Mega', pix:89.99, boleto:89.99},
    {id:'P3', vel:1000, label:'1000 Mega', pix:99.99, boleto:99.99},
  ]
};

const grupo = GRUPO_POR_CIDADE[cidadeNorm] || null;

// Cidade fora da area -> nao tem como validar; sinaliza transbordo
if (!grupo) {
  return [{ json: {
    cidade: cidade,
    grupo: null,
    atende: false,
    transbordo: true,
    motivo: 'cidade_fora_area',
    planos: [],
    catalogo_json: '[]',
    plano_match_id: null,
    plano_match_label: null,
    camada1_ok: false,
  }}];
}

const planos = PLANOS[grupo];

let mensagem = '';
try { mensagem = $('Entrada').first().json.mensagem || ''; } catch(e) {}
mensagem = String(mensagem).trim().toLowerCase();

let planoMatched = null;

// Tentativa 1: numero direto (1-9)
const numMatch = mensagem.match(/^\s*(\d+)\s*$/);
if (numMatch) {
  const idx = parseInt(numMatch[1], 10) - 1;
  if (idx >= 0 && idx < planos.length) {
    planoMatched = planos[idx];
  }
}

// Tentativa 2: velocidade exata ("400", "600" ou "1000") — so vale se houver UM unico plano daquela velocidade
if (!planoMatched) {
  for (const vel of [400, 600, 1000]) {
    const regex = new RegExp(`\\b${vel}\\b`);
    if (regex.test(mensagem)) {
      const cands = planos.filter(p => p.vel === vel);
      if (cands.length === 1) { planoMatched = cands[0]; break; }
    }
  }
}

return [{ json: {
  cidade: cidade,
  grupo: grupo,
  atende: true,
  transbordo: false,
  planos: planos,
  catalogo_json: JSON.stringify(planos),
  plano_match_id: planoMatched ? planoMatched.id : null,
  plano_match_label: planoMatched ? planoMatched.label : null,
  camada1_ok: !!planoMatched,
}}];

