// ValidarCPF — regex 11 digitos + algoritmo dig verificador
let raw = '';
try { raw = $('Entrada').first().json.mensagem || ''; } catch(e) {}
const limpo = String(raw).replace(/\D/g, '');
let valido = false;
if (limpo.length === 11 && !/^(\d)\1{10}$/.test(limpo)) {
  // Algoritmo CPF
  let soma1 = 0, soma2 = 0;
  for (let i = 0; i < 9; i++) {
    soma1 += parseInt(limpo[i]) * (10 - i);
    soma2 += parseInt(limpo[i]) * (11 - i);
  }
  let d1 = (soma1 * 10) % 11;
  if (d1 === 10) d1 = 0;
  soma2 += d1 * 2;
  let d2 = (soma2 * 10) % 11;
  if (d2 === 10) d2 = 0;
  valido = (d1 === parseInt(limpo[9]) && d2 === parseInt(limpo[10]));
}
return [{ json: {
  cpf_input: raw,
  cpf_limpo: limpo,
  cpf_valido: valido,
}}];

// ValidarDataDeNascimento — regex DD/MM/AAAA + maioridade
let raw = '';
try { raw = $('Entrada').first().json.mensagem || ''; } catch(e) {}
const s = String(raw).trim();
const re = /^(\d{1,2})[\/\-\.](\d{1,2})[\/\-\.](\d{2,4})$/;
const m = s.match(re);
let valido = false;
let formatted = '';
let isOver18 = false;
if (m) {
  let d = parseInt(m[1]), mes = parseInt(m[2]), a = parseInt(m[3]);
  if (a < 100) a += (a > 50 ? 1900 : 2000);
  const dt = new Date(a, mes - 1, d);
  if (dt.getFullYear() === a && dt.getMonth() === mes - 1 && dt.getDate() === d) {
    valido = true;
    formatted = `${String(d).padStart(2,'0')}/${String(mes).padStart(2,'0')}/${a}`;
    const hoje = new Date();
    const idade = hoje.getFullYear() - a - ((hoje.getMonth() < mes - 1 || (hoje.getMonth() === mes - 1 && hoje.getDate() < d)) ? 1 : 0);
    isOver18 = idade >= 18;
  }
}
return [{ json: {
  data_input: raw,
  data_formatted: formatted,
  data_valida: valido,
  is_over_18: isOver18,
  camada1_ok: valido && isOver18,
}}];

// GerarCatalogoPlanos — gera grupo, planos e lista formatada (Brayo)
// Le cidade de duas fontes: HTTP ViaCEP (turno do CEP) ou Load Session.dados.cidade (turno do plano)
function normCidade(s) {
  return (s || '').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '');
}
let cidade = '';
try { cidade = $('HTTP ViaCEP').first().json.localidade; } catch(e) {}
if (!cidade) { try { cidade = $('Load Session').first().json.dados.cidade; } catch(e) {} }
const cidadeNorm = normCidade(cidade);

// Brayo atende somente estas cidades. Demais -> transbordo humano.
const GRUPO_POR_CIDADE = {
  'lencois paulista': 'BRAYO',
  'macatuba':         'BRAYO',
  'pederneiras':      'BRAYO',
};

const PLANOS = {
  BRAYO: [
    {id:'P1', vel:400,  label:'400 Mega', pix:74.99, boleto:74.99},
    {id:'P2', vel:600,  label:'600 Mega', pix:89.99, boleto:89.99},
    {id:'P3', vel:1000, label:'1000 Mega', pix:99.99, boleto:99.99},
  ]
};

const grupo = GRUPO_POR_CIDADE[cidadeNorm] || null;

// Cidade fora da area -> sinaliza transbordo (nodos a jusante decidem)
if (!grupo) {
  return [{ json: {
    cidade: cidade,
    grupo: null,
    atende: false,
    transbordo: true,
    motivo: 'cidade_fora_area',
    planos: [],
    catalogo_json: '[]',
    lista_formatada: 'Ainda nao atendemos sua regiao. Vou te transferir para um atendente.',
  }}];
}

const planos = PLANOS[grupo];
const EMOJI_NUM = ['1️⃣','2️⃣','3️⃣','4️⃣','5️⃣','6️⃣','7️⃣','8️⃣','9️⃣'];
const lista_formatada = '📶 *Planos disponíveis:*\n\n' + planos.map((p, i) => {
  const num = EMOJI_NUM[i] || `${i+1}.`;
  const pix = p.pix.toFixed(2).replace('.', ',');
  return `${num} ${p.label} por R$ ${pix}`;
}).join('\n\n');

return [{ json: {
  cidade: cidade,
  grupo: grupo,
  atende: true,
  transbordo: false,
  planos: planos,
  catalogo_json: JSON.stringify(planos),
  lista_formatada: lista_formatada,
}}];

// PegarRespostaBot — extrai resposta_bot de qualquer Step que rodou
const STEPS = [
  'SmartSkip',
  'Step Aguarda Humano', 'Step Pergunta Pos Concluido', 'Step Novo Pedido', 'Step Humano Pos Concluido', 'Step Reasking Pos Concluido', 'Step Corrigir Nome', 'Step Corrigir Cep', 'Step Corrigir Numero', 'Step Corrigir Complemento', 'Step Corrigir Plano', 'Step Corrigir Cpf', 'Step Corrigir Data nasc', 'Step Corrigir Email', 'Step Corrigir Rg', 'Step Reasking Corrigir',
  'Step Inicio', 'Step Aguarda Nome', 'Step Reasking Nome',
  'Step Aguarda CEP', 'Step Reasking CEP Formato', 'Step Reasking CEP NaoExiste', 'Step Reasking CEP SemCobertura', 'Step Reasking CEP (via IA)',
  'Step Confirma Sim', 'Step Confirma Nao', 'Step Reasking Confirma',
  'Step Aguarda Numero', 'Step Aguarda Complemento',
  'Step Aguarda Plano', 'Step Aguarda Plano (via IA)', 'Step Reasking Plano',
  'Step Aguarda CPF', 'Step Aguarda CPF (via IA)', 'Step Reasking CPF',
  'Step Aguarda Data Nasc', 'Step Aguarda Data Nasc (via IA)', 'Step Reasking Data Nasc',
  'Step Aguarda RG Frente', 'Step Reasking RG Frente', 'Step Aguarda RG Verso', 'Step Reasking RG Verso',
  'Step Aguarda Email (Final)', 'Step Aguarda Email (via IA)', 'Step Reasking Email (via IA)',
  'Step Final Concluido', 'Step Final Reiniciar', 'Step Reasking Confirma Final',
];
let resposta_bot = '';
for (const s of STEPS) {
  try {
    const v = $(s).first().json.resposta_bot;
    if (v) { resposta_bot = v; break; }
  } catch (e) {}
}
const ss = $input.first().json;
// Se o SmartSkip (nodo anterior) ja gerou resposta_bot — ex: pulou pro
// resumo final apos uma correcao — ela tem prioridade sobre o loop de Steps.
const resposta_final = (ss && ss.resposta_bot) ? ss.resposta_bot : resposta_bot;
return [{ json: { ...ss, resposta_bot: resposta_final } }];

// DetectarReset — reseta sessao SO se cliente pedir explicitamente
const ss = $input.first().json;
let mensagem = '';
try { mensagem = String($('Entrada').first().json.mensagem || '').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, ''); } catch(e) {}

// Reset SO com palavras explicitas — "oi"/"ola" NAO reseta
const COMANDOS_RESET = [
  'recomecar', 'recomeçar', 'reiniciar', 'reset', 'menu',
  'comecar de novo', 'começar de novo', 'do zero',
  'apagar tudo', 'limpar', 'comecar tudo de novo',
];
const eh_reset = COMANDOS_RESET.some(c => mensagem === c || mensagem.includes(c));

if (eh_reset && ss.nodo_atual !== 'inicio') {
  return [{ json: { ...ss, nodo_atual: 'inicio', dados: {}, _reset: true } }];
}
return [{ json: ss }];

// ClassificarConfirmacao — yes/no em pt-br
let raw = '';
try { raw = $('Entrada').first().json.mensagem || ''; } catch(e) {}
const m = String(raw).trim().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const SIMs = ['sim', 's', 'isso', 'isso ai', 'isso mesmo', 'esta certo', 'ta certo', 'confirmo', 'correto',
              'ok', 'okay', 'beleza', 'show', 'positivo', 'eh isso', 'aham', 'uhum', 'pode ser',
              'esta correto', 'ta correto', 'ta', 'yes', 'y', '👍'];
